package com.lightevents.payments;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="transactions")
public class Transaction { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String reference=UUID.randomUUID().toString(); private Long eventId; private Long attendeeId; @Enumerated(EnumType.STRING) private PaymentProvider provider; @Enumerated(EnumType.STRING) private PaymentStatus status=PaymentStatus.INITIATED; private BigDecimal amount; private String currency="XOF"; private String payerPhone; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getReference(){return reference;} public Long getEventId(){return eventId;} public void setEventId(Long v){eventId=v;} public Long getAttendeeId(){return attendeeId;} public void setAttendeeId(Long v){attendeeId=v;} public PaymentProvider getProvider(){return provider;} public void setProvider(PaymentProvider v){provider=v;} public PaymentStatus getStatus(){return status;} public void setStatus(PaymentStatus v){status=v;} public BigDecimal getAmount(){return amount;} public void setAmount(BigDecimal v){amount=v;} public String getCurrency(){return currency;} public void setCurrency(String v){currency=v;} public String getPayerPhone(){return payerPhone;} public void setPayerPhone(String v){payerPhone=v;} public Instant getCreatedAt(){return createdAt;} }
